import{_ as t,o as e,c as r,a2 as d}from"./chunks/framework.ZhLefgN8.js";const b=JSON.parse('{"title":"货币基金交易规则","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/money-market-fund-rules.md","filePath":"zh-CN/funds-and-wealth/money-market-fund-rules.md"}'),o={name:"funds-and-wealth/money-market-fund-rules.md"};function l(n,a,h,i,s,u){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="货币基金交易规则" tabindex="-1">货币基金交易规则 <a class="header-anchor" href="#货币基金交易规则" aria-label="Permalink to &quot;货币基金交易规则&quot;">​</a></h1><p>货币基金 09:05 交易截止时间、买卖规则及撤单规则说明。</p><h2 id="与普通基金的区别" tabindex="-1">与普通基金的区别 <a class="header-anchor" href="#与普通基金的区别" aria-label="Permalink to &quot;与普通基金的区别&quot;">​</a></h2><p>货币基金的每日交易截止时间为 <strong>09:05（北京时间）</strong>，早于普通基金的 12:00 截止时间。其他基金类型请参考《基金买入与卖出规则》。</p><h2 id="买入规则" tabindex="-1">买入规则 <a class="header-anchor" href="#买入规则" aria-label="Permalink to &quot;买入规则&quot;">​</a></h2><h3 id="手动买入流程" tabindex="-1">手动买入流程 <a class="header-anchor" href="#手动买入流程" aria-label="Permalink to &quot;手动买入流程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间节点</th><th>说明</th></tr></thead><tbody><tr><td>T 日 09:05 前提交</td><td>按 T 日净值确认份额</td></tr><tr><td>T 日 09:05 后提交</td><td>顺延至下一交易日按 T+1 日净值处理</td></tr></tbody></table><h2 id="卖出-赎回-规则" tabindex="-1">卖出（赎回）规则 <a class="header-anchor" href="#卖出-赎回-规则" aria-label="Permalink to &quot;卖出（赎回）规则&quot;">​</a></h2><h3 id="手动卖出流程" tabindex="-1">手动卖出流程 <a class="header-anchor" href="#手动卖出流程" aria-label="Permalink to &quot;手动卖出流程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间节点</th><th>说明</th></tr></thead><tbody><tr><td>T 日 09:05 前提交</td><td>按 T 日净值确认卖出金额</td></tr><tr><td>T 日 09:05 后提交</td><td>顺延至下一交易日按 T+1 日净值处理</td></tr></tbody></table><h2 id="撤单规则" tabindex="-1">撤单规则 <a class="header-anchor" href="#撤单规则" aria-label="Permalink to &quot;撤单规则&quot;">​</a></h2><ul><li>T 日 <strong>09:05 前</strong>：可撤销尚未确认的买入或卖出申请</li><li>T 日 <strong>09:05 后</strong>：申请不可撤单，将按下一交易日处理</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/余额通交易规则">余额通交易规则</a> — 余额通是货币基金产品</li></ul>',14)])])}const f=t(o,[["render",l]]);export{b as __pageData,f as default};
